#!/usr/bin/env node
/**
 * add_xcsc_comp_bilingual.js — Add English bilingual fields to xcsc_composition_data.js
 *
 * Adds cn/en to techniques/structures, nameEn/labelEn/descEn to rubric,
 * promptEn/guideEn to topics, and titleEn/fullTextEn/metadata to essays.
 *
 * Usage: node build/add_xcsc_comp_bilingual.js
 */
const vm = require('vm');
const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, '..', 'xcsc_composition_data.js');
let code = fs.readFileSync(filePath, 'utf8');
// Fix unescaped single quotes inside single-quoted strings (Chinese book-title marks '…')
// Strategy: find 'text' patterns where inner ASCII single quotes break parsing
// Replace inner ASCII single quotes with Unicode LEFT/RIGHT SINGLE QUOTATION MARK
code = code.replace(/(fullText:\s*')([^]*?)('(?:,\s*\n|\n))/g, function(m, pre, inner, post) {
  // Escape any ASCII single quotes within fullText content
  return pre + inner.replace(/'/g, '\u2019') + post;
});
// Also fix any other string values with unescaped inner quotes
// More targeted: within string values, replace 'Chinese' pattern (quote-Chinese-quote)
code = code.replace(/这叫'([^']+)'/g, '这叫\u2018$1\u2019');
const ctx = { window: {} };
vm.runInNewContext(code, ctx);
const D = ctx.window.XCSC_COMP_DATA;

// ═══════════════════════════════════════════════════════════
// Technique — add cn (alias for name) and descEn
// ═══════════════════════════════════════════════════════════
