// ═══════════════════════════════════════════════════════════
// Apply all translations
// ═══════════════════════════════════════════════════════════
function applyTranslations() {
  // 1. Techniques: add cn (= name), descEn
  var techs = D.techniques || {};
  Object.keys(techs).forEach(function(k) {
    var t = techs[k];
    t.cn = t.name;
    if (TECH_DESC_EN[k]) t.descEn = TECH_DESC_EN[k];
  });

  // 2. Structures: add cn (= name), en, descEn, stepsEn
  var structs = D.structures || {};
  Object.keys(structs).forEach(function(k) {
    var s = structs[k];
    s.cn = s.name;
    if (STRUCT_EN[k]) {
      s.en = STRUCT_EN[k].en;
      s.descEn = STRUCT_EN[k].descEn;
      s.stepsEn = STRUCT_EN[k].stepsEn;
    }
  });

  // 3. Rubric: add nameEn, level labelEn + descEn
  var dims = (D.rubric && D.rubric.dimensions) || [];
  dims.forEach(function(d) {
    if (RUBRIC_EN[d.id]) {
      d.nameEn = RUBRIC_EN[d.id].nameEn;
      (d.levels || []).forEach(function(lv, i) {
        var en = (RUBRIC_EN[d.id].levels || [])[i];
        if (en) { lv.labelEn = en.labelEn; lv.descEn = en.descEn; }
      });
    }
  });

  // 4. Topics + Essays
  var topics = D.topics || [];
  var applied = 0;
  topics.forEach(function(topic) {
    var tr = TOPICS[topic.id];
    if (!tr) return;
    applied++;
    if (tr.promptEn) topic.promptEn = tr.promptEn;
    if (tr.contextEn) topic.contextEn = tr.contextEn;
    topic.categoryEn = CAT_EN[topic.category] || '';

    // Guide
    if (tr.guide && topic.guide) {
      if (tr.guide.analysisEn) topic.guide.analysisEn = tr.guide.analysisEn;
      if (tr.guide.pitfallsEn) topic.guide.pitfallsEn = tr.guide.pitfallsEn;
      if (tr.guide.keyPointsEn) topic.guide.keyPointsEn = tr.guide.keyPointsEn;
    }

    // Essays
    if (tr.essays && topic.essays) {
      topic.essays.forEach(function(es, ei) {
        var etr = tr.essays[ei];
        if (!etr) return;
        if (etr.titleEn) es.titleEn = etr.titleEn;
        if (etr.fullTextEn) es.fullTextEn = etr.fullTextEn;
        if (etr.sections && es.sections) {
          es.sections.forEach(function(s, si) {
            var str = etr.sections[si];
            if (str && str.fnEn) s.fnEn = str.fnEn;
          });
        }
        if (etr.principles && es.principles) {
          es.principles.forEach(function(p, pi) {
            var ptr = etr.principles[pi];
            if (ptr) { if (ptr.pointEn) p.pointEn = ptr.pointEn; if (ptr.detailEn) p.detailEn = ptr.detailEn; }
          });
        }
        if (etr.highlights && es.highlights) {
          es.highlights.forEach(function(h, hi) {
            var htr = etr.highlights[hi];
            if (htr) { if (htr.textEn) h.textEn = htr.textEn; if (htr.whyEn) h.whyEn = htr.whyEn; }
          });
        }
      });
    }
  });
  return applied;
}

// ═══════════════════════════════════════════════════════════
// Run
// ═══════════════════════════════════════════════════════════
var count = applyTranslations();
console.log('[comp-bilingual] Applied translations for ' + count + '/' + (D.topics || []).length + ' topics');
