// Serialize
function serializeJS(obj, indent) {
  indent = indent || 0;
  var pad = '';
  for (var i = 0; i < indent; i++) pad += '  ';
  if (obj === null || obj === undefined) return 'null';
  if (typeof obj === 'number' || typeof obj === 'boolean') return String(obj);
  if (typeof obj === 'string') return "'" + obj.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/\n/g, '\\n') + "'";
  if (Array.isArray(obj)) {
    if (obj.length === 0) return '[]';
    // Short arrays of primitives
    if (obj.length <= 6 && obj.every(function(x) { return typeof x === 'string' && x.length < 30; })) {
      return '[' + obj.map(function(x) { return serializeJS(x); }).join(',') + ']';
    }
    var items = obj.map(function(item) { return pad + '  ' + serializeJS(item, indent + 1); });
    return '[\n' + items.join(',\n') + '\n' + pad + ']';
  }
  if (typeof obj === 'object') {
    var keys = Object.keys(obj);
    if (keys.length === 0) return '{}';
    // Short objects
    var totalLen = keys.reduce(function(s, k) { return s + k.length + (typeof obj[k] === 'string' ? obj[k].length : 10); }, 0);
    if (totalLen < 80 && keys.length <= 4 && keys.every(function(k) { return typeof obj[k] !== 'object' || obj[k] === null; })) {
      return '{' + keys.map(function(k) { return k + ':' + serializeJS(obj[k]); }).join(', ') + '}';
    }
    var entries = keys.map(function(k) {
      var safe = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/.test(k) ? k : "'" + k + "'";
      return pad + '  ' + safe + ': ' + serializeJS(obj[k], indent + 1);
    });
    return '{\n' + entries.join(',\n') + '\n' + pad + '}';
  }
  return String(obj);
}

var header = '/**\n * xcsc_composition_data.js — 小升初作文范文与写作指导数据\n * Bilingual (Chinese + English)\n * Generated by build/add_xcsc_comp_bilingual.js\n */\n';
var out = header + 'window.XCSC_COMP_DATA = ' + serializeJS(D) + ';\n';
fs.writeFileSync(filePath, out, 'utf8');
var kb = Math.round(Buffer.byteLength(out, 'utf8') / 1024 * 10) / 10;
console.log('[comp-bilingual] Written ' + kb + ' KB to xcsc_composition_data.js');
